# Car placeholder images - Base64 encoded small car icons
car_placeholder_1 = "data:image/svg+xml;base64,"

car_placeholder_2 = "data:image/svg+xml;base64,"

car_placeholder_3 = "data:image/svg+xml;base64,"

# Dictionary mapping car brand/model to placeholder images
CAR_IMAGES = {
    ("Toyota", "Camry"): car_placeholder_1,
    ("Honda", "Accord"): car_placeholder_2,
    ("Toyota", "RAV4"): car_placeholder_3,
    ("Mercedes-Benz", "S-Class"): car_placeholder_1,
    ("BMW", "7 Series"): car_placeholder_2,
    ("Audi", "A8"): car_placeholder_3,
    ("Porsche", "911 Carrera"): car_placeholder_1,
    ("Chevrolet", "Corvette"): car_placeholder_2,
    ("Jeep", "Wrangler"): car_placeholder_3,
    ("Tesla", "Model S"): car_placeholder_1,
    ("Nissan", "Leaf"): car_placeholder_2,
    ("Ford", "F-150"): car_placeholder_3,
    ("Hyundai", "Elantra"): car_placeholder_1,
    ("Kia", "Forte"): car_placeholder_2
}

def get_car_placeholder_image(brand, model):
    """Get a placeholder image for a car"""
    key = (brand, model)
    if key in CAR_IMAGES:
        return CAR_IMAGES[key]
    
    # Return a default based on hash of brand+model
    placeholders = [car_placeholder_1, car_placeholder_2, car_placeholder_3]
    index = hash(brand + model) % len(placeholders)
    return placeholders[index]